/**
 * @param {number[]} nums
 * @param {number[][]} edges
 * @return {number}
 */
function solve(nums, edges) {
    const n = nums.length;

    // Build adjacency list for the graph
    const adj = Array(n).fill(0).map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let count = 0;

    // Iterate over all non-empty subsets of nodes.
    // Since N <= 13, we can iterate from 1 to 2^N - 1.
    const numSubsets = 1 << n;

    for (let i = 1; i < numSubsets; i++) {
        // i represents the bitmask for the subset s

        // 1. Check the sum of values (parity)
        let sum = 0;
        for (let j = 0; j < n; j++) {
            if ((i >> j) & 1) {
                sum += nums[j];
            }
        }

        if (sum % 2 !== 0) {
            continue; // Sum is odd, skip this subset
        }

        // 2. Check connectivity of the induced subgraph

        // Find the first node in the subset s (the starting node for BFS/DFS)
        let startNode = -1;
        for (let j = 0; j < n; j++) {
            if ((i >> j) & 1) {
                startNode = j;
                break;
            }
        }

        if (startNode === -1) continue; // Should not happen since i >= 1

        // Perform BFS/DFS restricted to nodes in the subset s
        const visited = new Array(n).fill(false);
        const queue = [startNode];
        visited[startNode] = true;
        let visitedCount = 0;

        while (queue.length > 0) {
            const u = queue.shift();
            visitedCount++;

            // Check neighbors of u
            for (const v of adj[u]) {
                // A neighbor v must satisfy two conditions to be considered in the induced subgraph:
                // 1. v must be in the subset s (i.e., the v-th bit of i must be set).
                // 2. v must not have been visited yet.
                if (((i >> v) & 1) && !visited[v]) {
                    visited[v] = true;
                    queue.push(v);
                }
            }
        }

        // Count the total number of nodes in the subset s
        let subsetSize = 0;
        for (let j = 0; j < n; j++) {
            if ((i >> j) & 1) {
                subsetSize++;
            }
        }

        // The induced subgraph is connected if the number of reachable nodes from the start node
        // within the subset s equals the total size of the subset s.
        if (visitedCount === subsetSize) {
            count++;
        }
    }

    return count;
}

